---
import type { HTMLAttributes } from "astro/types"

import { cn } from "@/lib/utils"

type Props = HTMLAttributes<"div"> & {
  defaultOpen?: boolean
  open?: boolean
  delay?: number
  skipDelayDuration?: number
  closeDelay?: number
  side?: "top" | "right" | "bottom" | "left"
  align?: "start" | "center" | "end"
  sideOffset?: number
  alignOffset?: number
  avoidCollisions?: boolean
  collisionPadding?: number
  portal?: boolean
  closeOnClickOutside?: boolean
  closeOnEscape?: boolean
}

const {
  class: className,
  defaultOpen,
  open,
  delay = 300,
  skipDelayDuration = 300,
  closeDelay = 300,
  side = "bottom",
  align = "center",
  sideOffset = 4,
  alignOffset = 4,
  avoidCollisions = true,
  collisionPadding = 8,
  portal = true,
  closeOnClickOutside = true,
  closeOnEscape = true,
  ...props
} = Astro.props
---

<div
  data-slot="hover-card"
  data-default-open={defaultOpen}
  data-open={open}
  data-delay={delay}
  data-skip-delay-duration={skipDelayDuration}
  data-close-delay={closeDelay}
  data-side={side}
  data-align={align}
  data-side-offset={sideOffset}
  data-align-offset={alignOffset}
  data-avoid-collisions={avoidCollisions}
  data-collision-padding={collisionPadding}
  data-portal={portal}
  data-close-on-click-outside={closeOnClickOutside}
  data-close-on-escape={closeOnEscape}
  class={cn(className)}
  {...props}
>
  <slot />
</div>

<script>
  import { create } from "@data-slot/hover-card"

  create()
</script>

---
import type { HTMLAttributes } from "astro/types"

import { cn } from "@/lib/utils"

type Props = HTMLAttributes<"div"> & {
  side?: "top" | "right" | "bottom" | "left"
  align?: "start" | "center" | "end"
  sideOffset?: number
  alignOffset?: number
  avoidCollisions?: boolean
  collisionPadding?: number
}

const {
  class: className,
  hidden = true,
  side = "bottom",
  align = "center",
  sideOffset = 4,
  alignOffset = 4,
  avoidCollisions,
  collisionPadding,
  ...props
} = Astro.props
---

<div data-slot="hover-card-portal">
  <div
    data-slot="hover-card-positioner"
    data-side={side}
    data-align={align}
    data-side-offset={sideOffset}
    data-align-offset={alignOffset}
    data-avoid-collisions={avoidCollisions}
    data-collision-padding={collisionPadding}
    class="isolate z-50"
  >
    <div
      data-slot="hover-card-content"
      hidden={hidden}
      class={cn(
        "z-50 w-64 origin-(--transform-origin) rounded-lg bg-popover p-4 text-sm text-popover-foreground shadow-md ring-1 ring-foreground/10 outline-hidden duration-100 data-[side=bottom]:slide-in-from-top-2 data-[side=left]:slide-in-from-right-2 data-[side=right]:slide-in-from-left-2 data-[side=top]:slide-in-from-bottom-2 data-open:animate-in data-open:fade-in-0 data-open:zoom-in-95 data-closed:animate-out data-closed:fade-out-0 data-closed:zoom-out-95",
        className
      )}
      {...props}
    >
      <slot />
    </div>
  </div>
</div>

---
import type { HTMLAttributes } from "astro/types"

import { cn } from "@/lib/utils"

type Props = HTMLAttributes<"button"> &
  HTMLAttributes<"a"> &
  HTMLAttributes<"div"> &
  HTMLAttributes<"span"> & {
    as?: "a" | "button" | "div" | "span"
    href?: string
  }

const {
  as: explicitTag,
  class: className,
  type,
  ...props
} = Astro.props as Props

const Tag = explicitTag || ("href" in Astro.props ? "a" : "button")
---

<Tag
  data-slot="hover-card-trigger"
  type={Tag === "button" ? type || "button" : undefined}
  class={cn(className)}
  {...props}
>
  <slot />
</Tag>
